@Service
public class ProductServiceImpl implements ProductService {

    private static final String PRODUCT_INDEX = "products";
    private static final String SEARCH_LOG_INDEX = "search_queries";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductServiceImpl(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    @Override
    public void createIndicesIfNotExist() throws IOException {
        createProductIndexIfNeeded();
        createSearchLogIndexIfNeeded();
    }

    private void createProductIndexIfNeeded() throws IOException {
        GetIndexRequest getIndexRequest = new GetIndexRequest(PRODUCT_INDEX);
        boolean exists = client.indices().exists(getIndexRequest, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest(PRODUCT_INDEX);
            createIndexRequest.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0));
            XContentBuilder mapping = XContentFactory.jsonBuilder()
                    .startObject()
                    .startObject("properties")
                    .startObject("id").field("type", "keyword").endObject()
                    .startObject("name").field("type", "text").field("analyzer", "standard").endObject()
                    .startObject("description").field("type", "text").endObject()
                    .startObject("brand").field("type", "keyword").endObject()
                    .startObject("category").field("type", "keyword").endObject()
                    .startObject("tags").field("type", "keyword").endObject()
                    .startObject("price").field("type", "scaled_float").field("scaling_factor", 100).endObject()
                    .startObject("currency").field("type", "keyword").endObject()
                    .startObject("stock").field("type", "integer").endObject()
                    .startObject("rating").field("type", "double").endObject()
                    .startObject("active").field("type", "boolean").endObject()
                    .startObject("createdAt").field("type", "date").endObject()
                    .startObject("updatedAt").field("type", "date").endObject()
                    .endObject()
                    .endObject();
            createIndexRequest.mapping(mapping);
            client.indices().create(createIndexRequest, RequestOptions.DEFAULT);
        }
    }

    private void createSearchLogIndexIfNeeded() throws IOException {
        GetIndexRequest getIndexRequest = new GetIndexRequest(SEARCH_LOG_INDEX);
        boolean exists = client.indices().exists(getIndexRequest, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest(SEARCH_LOG_INDEX);
            createIndexRequest.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0));
            XContentBuilder mapping = XContentFactory.jsonBuilder()
                    .startObject()
                    .startObject("properties")
                    .startObject("id").field("type", "keyword").endObject()
                    .startObject("userId").field("type", "keyword").endObject()
                    .startObject("query").field("type", "text").endObject()
                    .startObject("filters").field("type", "object").endObject()
                    .startObject("searchedAt").field("type", "date").endObject()
                    .endObject()
                    .endObject();
            createIndexRequest.mapping(mapping);
            client.indices().create(createIndexRequest, RequestOptions.DEFAULT);
        }
    }

    @Override
    public void indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        if (product.getCreatedAt() == null) {
            product.setCreatedAt(Instant.now());
        }
        product.setUpdatedAt(Instant.now());

        IndexRequest request = new IndexRequest(PRODUCT_INDEX)
                .id(product.getId())
                .source(objectMapper.writeValueAsString(product), org.elasticsearch.common.xcontent.XContentType.JSON);
        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
    }

    @Override
    public void bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Product product : products) {
            if (product.getId() == null || product.getId().isBlank()) {
                product.setId(UUID.randomUUID().toString());
            }
            if (product.getCreatedAt() == null) {
                product.setCreatedAt(Instant.now());
            }
            product.setUpdatedAt(Instant.now());
            bulkRequest.add(new IndexRequest(PRODUCT_INDEX)
                    .id(product.getId())
                    .source(objectMapper.writeValueAsString(product), org.elasticsearch.common.xcontent.XContentType.JSON));
        }
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
    }

    @Override
    public ProductSearchResponse searchProducts(ProductSearchRequest request, String userId) throws IOException {
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery()
                .filter(QueryBuilders.termQuery("active", true));

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(request.getQuery(), "name^3", "description", "brand", "category", "tags"));
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", request.getBrand()));
        }
        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("category", request.getCategory()));
        }
        if (request.getTags() != null && !request.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", request.getTags()));
        }
        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            org.elasticsearch.index.query.RangeQueryBuilder range = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                range.gte(request.getMinPrice());
            }
            if (request.getMaxPrice() != null) {
                range.lte(request.getMaxPrice());
            }
            boolQuery.filter(range);
        }

        int page = request.getPage() == null ? 0 : Math.max(request.getPage(), 0);
        int size = request.getSize() == null ? 20 : Math.min(Math.max(request.getSize(), 1), 100);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder()
                .query(boolQuery)
                .from(page * size)
                .size(size)
                .fetchSource(new FetchSourceContext(true, new String[]{"id","name","description","brand","category","tags","price","currency","stock","rating","active","createdAt","updatedAt"}, new String[]{}))
                .sort("rating", SortOrder.DESC)
                .aggregation(AggregationBuilders.terms("brands").field("brand").size(20))
                .aggregation(AggregationBuilders.terms("categories").field("category").size(20))
                .aggregation(AggregationBuilders.terms("tags").field("tags").size(20));

        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX).source(sourceBuilder);
        SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = Arrays.stream(searchResponse.getHits().getHits())
                .map(hit -> {
                    try {
                        Product p = objectMapper.readValue(hit.getSourceAsString(), Product.class);
                        p.setId(hit.getId());
                        return p;
                    } catch (Exception e) {
                        throw new RuntimeException(e);
                    }
                })
                .collect(Collectors.toList());

        Map<String, Map<String, Long>> facets = new HashMap<>();
        Terms brands = searchResponse.getAggregations().get("brands");
        Terms categories = searchResponse.getAggregations().get("categories");
        Terms tags = searchResponse.getAggregations().get("tags");

        facets.put("brand", extractTerms(brands));
        facets.put("category", extractTerms(categories));
        facets.put("tags", extractTerms(tags));

        if (userId != null || (request.getQuery() != null && !request.getQuery().isBlank())) {
            SearchQueryLog log = new SearchQueryLog(
                    UUID.randomUUID().toString(),
                    userId,
                    request.getQuery(),
                    objectMapper.convertValue(request, new TypeReference<Map<String, Object>>() {}),
                    Instant.now()
            );
            logSearchQuery(log);
        }

        return new ProductSearchResponse(products, searchResponse.getHits().getTotalHits() != null ? searchResponse.getHits().getTotalHits().value : 0L, facets);
    }

    private Map<String, Long> extractTerms(Terms terms) {
        Map<String, Long> result = new LinkedHashMap<>();
        if (terms == null) {
            return result;
        }
        for (Terms.Bucket bucket : terms.getBuckets()) {
            result.put(bucket.getKeyAsString(), bucket.getDocCount());
        }
        return result;
    }

    @Override
    public void logSearchQuery(SearchQueryLog searchQueryLog) throws IOException {
        if (searchQueryLog.getId() == null || searchQueryLog.getId().isBlank()) {
            searchQueryLog.setId(UUID.randomUUID().toString());
        }
        if (searchQueryLog.getSearchedAt() == null) {
            searchQueryLog.setSearchedAt(Instant.now());
        }
        IndexRequest request = new IndexRequest(SEARCH_LOG_INDEX)
                .id(searchQueryLog.getId())
                .source(objectMapper.writeValueAsString(searchQueryLog), org.elasticsearch.common.xcontent.XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }
}

package com.example.ecommercesearch.controller;

import com.example.ecommercesearch.dto.ProductSearchRequest;
import com.example.ecommercesearch.dto.ProductSearchResponse;
import com.example.ecommercesearch.model.Product;
import com.example.ecommercesearch.model.SearchQueryLog;
import com.example.ecommercesearch.service.ProductService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;
import java.util.Map;
import java.util.UUID;

@RestController
@RequestMapping("/api/search")
public class ProductSearchController {

    private final ProductService productService;

    public ProductSearchController(ProductService productService) {
        this.productService = productService;
    }

    @PostMapping("/index")
    public ResponseEntity<Void> indexProduct(@RequestBody Product product) throws IOException {
        productService.indexProduct(product);
        return ResponseEntity.ok().build();
    }

    @PostMapping("/bulk-index")
    public ResponseEntity<Void> bulkIndex(@RequestBody List<Product> products) throws IOException {
        productService.bulkIndexProducts(products);
        return ResponseEntity.ok().build();
    }

    @PostMapping
    public ResponseEntity<ProductSearchResponse> search(
            @RequestBody ProductSearchRequest request,
            @RequestHeader(value = "X-User-Id", required = false) String userId
    ) throws IOException {
        return ResponseEntity.ok(productService.searchProducts(request, userId));
    }

    @PostMapping("/log")
    public ResponseEntity<Void> logQuery(@RequestBody Map<String, Object> body,
                                         @RequestHeader(value = "X-User-Id", required = false) String userId) throws IOException {
        SearchQueryLog log = new SearchQueryLog(
                UUID.randomUUID().toString(),
                userId,
                (String) body.get("query"),
                body,
                java.time.Instant.now()
        );
        productService.logSearchQuery(log);
        return ResponseEntity.ok().build();
    }
}

